def parse(text):
    sections = []
    current_section = None
    
    for line in text.splitlines():
        line = line.strip()
        if not line:
            continue
            
        if not current_section:
            current_section = {"title": line, "paragraphs": [], "bullets": [], "paragraphsAfterBullets": []}
            sections.append(current_section)
        elif line.startswith("-") or re.match(r'^\d+\.', line):
            if line.startswith("- "):
                line = line[2:]
            
            # Identify if it's a bullet inside a num-bullet e.g. "- Покупка подписки"
            if len(current_section["bullets"]) == 0 and len(current_section["paragraphs"]) > 0 and current_section["paragraphs"][-1].startswith("- "):
                # Wait, this might be tricky, let's keep it simple: everything that starts with - or number is a bullet.
                pass
            current_section["bullets"].append(line)
        elif not line.startswith("-") and not re.match(r'^\d+\.', line):
            # It's a paragraph
            # if we have bullets already, it's after bullets
            # BUT: wait, if the section is a new title, it doesn't have a blank line sometimes? No, titles are separated by blank lines.
            if line.isupper() or line in ["Вступление", "Сфера Применения", "Изменение Условий", "Регистрация", "Содержимое", "Платежи", "Порядок Возврата Средств", "Запрещенные Категории Грузов и Реагирование на Нарушения", "Запрещенные Действия", "Обработка Персональных Данных", "Срок и прекращение", "Отказ", "Ответственность"]:
                current_section = {"title": line, "paragraphs": [], "bullets": [], "paragraphsAfterBullets": []}
                sections.append(current_section)
            else:
                if len(current_section["bullets"]) > 0:
                    current_section["paragraphsAfterBullets"].append(line)
                else:
                    current_section["paragraphs"].append(line)
    return sections

